firmware_template.source:
#include "vibration_sw420.h"
#include <Arduino.h>
#define VIB_PIN 13
static volatile uint32_t _cnt=0;static bool _det=false;static unsigned long _l=0;
void IRAM_ATTR _vib_isr(){_cnt++;}
void vibration_setup(){pinMode(VIB_PIN,INPUT);attachInterrupt(VIB_PIN,_vib_isr,RISING);Serial.println("[vib] OK");}
void vibration_loop(){if(millis()-_l<100)return;_l=millis();_det=!digitalRead(VIB_PIN);}
bool vibration_detected(){return _det;}
uint32_t vibration_count(){return _cnt;}
void vibration_reset(){_cnt=0;}
